  checkpoint:
    type: terrain
    properties:
      position_x:    { fixed_point: micro_units }
      position_y:    { fixed_point: micro_units }
      touched:       { type: boolean, default: false }

  secret_ember_pickup:
    type: terrain
    properties:
      position_x:    { fixed_point: micro_units }
      position_y:    { fixed_point: micro_units }
      effect:
        resource: { enum: [ember] }
        amount:   { type: integer, minimum: 1, maximum: 4 }
      discovered:    { type: boolean, default: false }
      visible:       { type: boolean, default: false }

verbs:
  jump:
    actor: "player_moth"
    cost: { resource: "ember", amount: 0 }
    target_schema: { type: input_event }
    effects:
      - { resolve: "jump_resolution" }
    feel: "jump"

  dash:
    actor: "player_moth"
    cost: { resource: "ember", amount: 3 }
    target_schema: { type: input_event }
    effects:
      - { resolve: "dash_resolution" }
