  advance_tick:
    actor: system
    cost: 0
    target_schema: { type: system }
    effects:
      - { resolve: "physics_tick" }

resources:
  hp:
    scope: per_run
    min: 0
    max: 1
    visibility: hud

  ember:
    scope: per_run
    min: 0
    max: 12
    velocity_target: "ember_velocity"
    visibility: hud

states:
  moth_movement:
    initial: grounded
    nodes:
